 * @createTime 2026-03-24
 * @bindingObjectLabel 任务明细
 * @bindingObjectApiName task_detail__c
 * @函数需求编号
 */

   String accId = context.data.customer__c as String;
    String taskMaterial = context.data.task_material__c as String;
    String dataId = context.data._id as String;
    String taskStatus = context.data.task_status__c as String;
    List taskOwner = context.data.owner as List;
