 * @函数需求编号
 */

String configId = context.data.this_task_configuration__c as String; 
String dataId = context.data._id as String;

def (Boolean error, Map data, String errorMessage) = Fx.object.findOne("rhythm_task__c", //对象apiName
            FQLAttribute.builder()
                    .columns(["_id", "task_interval__c"]) //需要返回的字段
                    .queryTemplate(QueryTemplate.AND(["_id": QueryOperator.EQ(configId)],["rhythm_task_type__c": QueryOperator.EQ("option_21d_cadence__c")])) //查询条件
                    .build(),
           SelectAttribute.builder()
                    .build())
    if (error) {
        log.error("未发现当前任务配置：" + errorMessage)
        return
    } else {
        def map = data as Map
        Integer interval = map["task_interval__c"] as Integer
        log.info("任务间隔：" + interval)

        String nextTaskTime = TaskDetailUtil.nextWorkingDay(DateTime.now() + interval.days)
        //Date nextDate = Date.of(nextTaskTime)
        DateTime nextDatetime = DateTime.of(nextTaskTime + (" 08:00"))
        //更新最后跟进时间
        Map updateData = [
                "next_follow_up_time__c":nextDatetime
        ]
        def (Boolean error1, Map data1, String errorMessage1) =  Fx.object.update("task_detail__c", dataId, updateData, UpdateAttribute.builder().triggerWorkflow(true).build())
        if (error1) {
            log.error("下次跟进时间更新失败：" + errorMessage1)
        }
    }

