 */
class TaskDetailUtil {

    //对外提供的方法
    static String nextWorkingDay(DateTime d1) {
        DateTime d2 = d1 + 20.days
        def (Boolean error,HttpResult result,String errorMessage) = 
                  Fx.proxy.callAPI('checkoffice.batchGetHoliday',  null, ["startTime":d1.toTimestamp(),"endTime":d2.toTimestamp()])

        List ret  = result["content"]["data"] as List
        def findResult = ret.find { it["isHolidayDay"] == 0 }
        String date = findResult ? (findResult["date"] as String): null

        return date
    }

    //debug 时候的入口方法
    static void main(String[] args) {
        DateTime d1 = DateTime.now + 4.days
        log.info(nextWorkingDay(d1))
    }

}

