    // URL 编码安全字符集（惰性初始化，规避 static {} 块限制）
    private static BitSet urlEncoder = null

    private static BitSet getUrlEncoder() {
        if (urlEncoder != null) {
            return urlEncoder
        }
        urlEncoder = new BitSet(256)
        "abcdefghijklmnopqrstuvwxyz".bytes.each { Byte b -> urlEncoder.set(b.intValue() & 0xFF) }
        "ABCDEFGHIJKLMNOPQRSTUVWXYZ".bytes.each { Byte b -> urlEncoder.set(b.intValue() & 0xFF) }
        "0123456789".bytes.each { Byte b -> urlEncoder.set(b.intValue() & 0xFF) }
        urlEncoder.set(45)
        urlEncoder.set(95)
        urlEncoder.set(46)
        urlEncoder.set(126)
        return urlEncoder
    }

