    static void cdpMapping(String value, List tempMappingList, Map updateData) {
        tempMappingList.each {
            itemMapping ->
                Map tempMapping = itemMapping as Map
                String type = tempMapping.type__c as String
                if (type == "option_text__c") {
                    updateData.put(tempMapping.crm_field_api__c as String, value)
                }
                if (type == "option_number__c") {
                    updateData.put(tempMapping.crm_field_api__c as String, value as BigDecimal)
                }
                if (type == "option_single_choice__c") {
                    Map check = tempMappingList.find { tm -> ((tm as Map).volcano_option_name__c as String) == (value as String) } as Map
                    if (check) {
                        updateData.put(tempMapping.crm_field_api__c as String, check?.crm_option_value_list__c)
                    }
                }
                if (type == "option_multiple_selection__c") {
                    Map check = tempMappingList.find { tm -> ((tm as Map).volcano_option_name__c as String) == (value as String) } as Map
                    if (check) {
                        List values = updateData[(tempMapping.crm_field_api__c as String)] as List
                        values = values ? values : []
                        values.add(check?.crm_option_value_list__c)
                        updateData.put(tempMapping.crm_field_api__c as String, values)
                    }
                }
                if (type == "option_date__c") {
                    Fx.log.debug("date---->>" + value)
                    updateData.put(tempMapping.crm_field_api__c as String, Date.of(value as String))
                }
                if (type == "option_date_time__c") {
                    Fx.log.debug("datetime---->>" + value)
                    Fx.log.debug("datetime---->>" + value)
                    if (value && value.length() == "2024-11-18 22:42:56".length()) {
                        value = value.substring(0, value.length() - 3)
                    }
                    updateData.put(tempMapping.crm_field_api__c as String, DateTime.of(value))
                }
                if (type == "option_boolean__c") {
                    //TODO 暂无此类型
                }
        }
    }

    /**
     * 根据USCC查询联系人标签
     * @param cId
     * @param uscc
     * @param projectId
     */
    static void flowContractByUscc(String cId, String uscc, int projectId) {
        String apiName = "ContactObj"
        List tagIds = []
        List mappingList = []
        List crmUpFields = []
        findCDPMapping(mappingList, tagIds, crmUpFields, apiName)
        if (!mappingList) {
            Fx.message.throwException("请先配置CDP标签映射表")
        }
        HttpResult usccToPhoneHttpResult = usccToPhoneList(uscc, projectId)
        Fx.log.info(usccToPhoneHttpResult)
        if (usccToPhoneHttpResult.statusCode != 200) {
            Fx.message.throwException("查询CDP客户标签失败，错误信息：" + usccToPhoneHttpResult)
        }
        def usccToPhoneContentDef = usccToPhoneHttpResult.content
        Map usccToPhoneContent = [:]
        if (usccToPhoneContentDef instanceof Map) {
            usccToPhoneContent = usccToPhoneContentDef as Map
        } else if (usccToPhoneContentDef instanceof String) {
            usccToPhoneContent = Fx.json.parse(usccToPhoneContentDef as String)
        }
        if ((usccToPhoneContent.code as Integer) != 0) {
            Fx.message.throwException("查询CDP客户标签失败，错误信息：" + usccToPhoneContent.message)
        }
        List allDatas = usccToPhoneContent.allData as List
        if (allDatas) {
            String findContractSQL = "select _id,name from ${apiName} where name in('${allDatas.join("','")}') and account_id = '${cId}'"
            List allContracts = []
            Fx.object.select(findContractSQL, SelectAttribute.builder().build(), {
                List list ->
                    allContracts.addAll(list)
            })
            List batchCreate = []
            Map batchUpdate = [:]
            allDatas.each {
                item ->
                    String phone = item as String
                    Map updateData = contractByPhone(phone, mappingList, tagIds, crmUpFields, projectId)
                    updateData.put("account_id", cId)
                    Map check = allContracts?.find { it -> ((it as Map).name as String) == phone } as Map
                    if (allContracts && check) {
                        batchUpdate.put(check._id as String, updateData)
                    } else {
                        batchCreate.add(updateData)
                    }
            }


            if (batchUpdate) {
                Fx.log.info("batchUpdate-------->>" + Fx.json.toJson(batchUpdate))
                //TODO 正式测试放开
                def updateContractRet = Fx.object.batchUpdate(apiName,batchUpdate,crmUpFields,BatchUpdateAttribute.builder().convert2SingleOperation(true).build())
                if(updateContractRet[0]) {
                    Fx.message.throwException("修改联系人标签失败：" + updateContractRet)
                }
                Fx.log.info("修改联系人标签结果：" + updateContractRet)
            }
            if (batchCreate) {
                Fx.log.info("batchCreate-------->>" + Fx.json.toJson(batchCreate))
                //TODO 正式测试放开
                def createContractRet = Fx.object.batchCreate(apiName,batchCreate, CreateAttribute.builder().build())
                if(createContractRet[0]) {
                    Fx.message.throwException("创建联系人标签失败：" + createContractRet)
                }
                Fx.log.info("修创建联系人标签结果：" + createContractRet)
            }
        } else {
            Fx.log.info("当前USCC下没有查到联系人： " + usccToPhoneContent)
        }
    }

    static void findCDPMapping(List mappingList, List tagIds, List crmUpFields, String apiName) {
        String sql = cdpMappingSQL + " and crm_object_api__c = '${apiName}'"
        Fx.object.select(sql, SelectAttribute.builder().build(), {
            List list ->
                tagIds.addAll(list?.findAll { l -> (l as Map).volcano_tag_id__c }?.collect {
                    l -> (l as Map).volcano_tag_id__c
                })
                mappingList.addAll(list)
                crmUpFields.addAll(list?.findAll { l -> (l as Map).crm_field_api__c }?.collect {
                    l -> (l as Map).crm_field_api__c
                })
        })
    }

    /**
     * 根据手机号查询联系人标签
     * @param phone
     * @param mappingList
     * @param tagIds
     * @param crmUpFields
     * @param projectId
     * @return
     */
    static Map contractByPhone(String phone, List mappingList, List tagIds, List crmUpFields, int projectId) {
        if (!tagIds || !mappingList || !crmUpFields) {
            String apiName = "ContactObj"
            findCDPMapping(mappingList, tagIds, crmUpFields, apiName)
        }
        HttpResult httpResult = contractQueryTags(phone, tagIds, projectId)
        if (httpResult.statusCode != 200) {
            Fx.message.throwException("查询CDP联系人标签失败，错误信息：" + httpResult)
        }
        def contentDef = httpResult.content
        Map content = [:]
        if (contentDef instanceof Map) {
            content = contentDef as Map
        } else if (contentDef instanceof String) {
            content = Fx.json.parse(contentDef as String)
        }
        if ((content.code as Integer) != 0) {
            Fx.message.throwException("查询CDP联系人标签失败，错误信息：" + content.message)
        }
        Map tags = content.tags as Map
        Map updateData = [:]
