    /**
     * ═══════════════════ doRequest：JSON 请求 ═══════════════════
     * @param method 请求方法 POST、GET
     * @param queryList 拼接参数
     * @param reqBody 请求体
     * @param action 接口Action
     * @param version 接口version
     * @param tenantId 企业ID
     * @return
     */
    HttpResult doRequest(String method, Map queryList, Map reqBody,
                         String action, String version, int tenantId) {
        String body = Fx.json.toJson(reqBody)
        String xContentSha256 = hashSHA256(body ?: "")
        DateTime now = DateTime.now()
        String formattedDateTime = (now as String) + ":" + (now.second > 10 ? now.second : "0" + now.second)
        formattedDateTime = formattedDateTime.replace("-", "").replace(" ", "T").replace(":", "") + "Z"
        String xDate = formattedDateTime
        String shortXDate = xDate.substring(0, 8)
        String contentType = "application/json"
        String signHeader = "x-date;x-content-sha256;content-type"

        TreeMap realQueryList = new TreeMap(queryList ?: [:])
        realQueryList.put("ApiAction", action)
        realQueryList.put("ApiVersion", version)
        String queryString = buildQueryString(realQueryList)

        String canonicalString = method + "\n" + path + "\n" + queryString + "\n" +
                "x-date:" + xDate + "\n" +
                "x-content-sha256:" + xContentSha256 + "\n" +
                "content-type:" + contentType + "\n" +
                "\n" + signHeader + "\n" + xContentSha256

        String hashCanonical = hashSHA256(canonicalString)
        String credentialScope = shortXDate + "/" + region + "/" + service + "/request"
        String signString = "HMAC-SHA256" + "\n" + xDate + "\n" + credentialScope + "\n" + hashCanonical

        byte[] signKey = genSigningSecretKeyV4(sk, shortXDate, region, service)
        String signature = hmacSHA256Hex(signKey, signString)

        String authorization = "HMAC-SHA256" +
                " Credential=" + ak + "/" + credentialScope +
                ", SignedHeaders=" + signHeader +
                ", Signature=" + signature

        String fullUrl = schema + "://" + host + path + "?" + queryString
        String traceId = "openapi_" + (queryList?.get("ApiAction") ?: "unknown") + "_" + System.currentTimeMillis()

        Request.RequestBuilder reqBuilder = Request.builder()
                .method(method).url(fullUrl).timeout(connectionTimeoutMs).retryCount(1)
                .header("Content-Type", contentType)
                .header("X-Date", xDate)
                .header("X-Content-Sha256", xContentSha256)
                .header("x-trace-id", traceId)
                .header("x-Tenant", String.valueOf(tenantId))

        if (sessionToken != null && !sessionToken.isEmpty()) {
            reqBuilder.header("X-Cdp-Security-Token", sessionToken)
        } else {
            reqBuilder.header("Authorization", authorization)
        }

        if (!"GET".equalsIgnoreCase(method) && body != null) {
            reqBuilder.body(StringBody.builder().content(body).build())
        }

        Request request = reqBuilder.build()
        Fx.log.info("[CDPUtils] 请求: " + method + " " + fullUrl + "\n" + Fx.json.toJson(request))
        def (Boolean error, HttpResult result, String message) = Fx.http.execute(request)

        if (error) {
            Fx.log.error("[CDPUtils] HTTP 请求失败: " + message)
            Fx.message.throwException("[CDPUtils] HTTP 请求失败: " + message)
        }

        int statusCode = result.statusCode
        String responseBody = ""
        if (result.content instanceof String) {
            responseBody = result.content as String
        } else if (result.content != null) {
            responseBody = Fx.json.toJson(result.content)
        }
        Fx.log.info("[CDPUtils] 响应码: " + statusCode + " 响应: " + responseBody)
        Fx.log.info("[CDPUtils] HTTP 请求结果: " + result)
        return result
    }

    static String hashSHA256(String input) {
        byte[] input1 = Fx.utils.toUTF8Bytes(input)
        return Fx.utils.encodeHex(Fx.crypto.SHA.sha256(input1)).toLowerCase()
    }

    static String hmacSHA256Hex(byte[] keyBaos, String content) {
        byte[] inputs = Fx.crypto.hmac.encrypt("HmacSHA256", keyBaos, content)
        return Fx.utils.encodeHex(inputs).toLowerCase()
    }

    /** HMAC-SHA256，密钥为 ByteArrayOutputStream，返回 ByteArrayOutputStream */
    static byte[] hmacSHA256Baos(byte[] keyBaos, String content) {
        byte[] inputs = Fx.crypto.hmac.encrypt("HmacSHA256", keyBaos, content)
        return inputs
    }

    /** V4 签名密钥链 */
    private static byte[] genSigningSecretKeyV4(String secretKey, String date, String region, String service) {
        byte[] skBaos = Fx.utils.toUTF8Bytes(secretKey)
        byte[] kDate = hmacSHA256Baos(skBaos, date)
        byte[] kRegion = hmacSHA256Baos(kDate, region)
        byte[] kService = hmacSHA256Baos(kRegion, service)
        return hmacSHA256Baos(kService, "request")
    }

    // ═══════════════════ 辅助方法 ═══════════════════

    /** RFC 3986 URL 编码 */
    private static String signStringEncoder(String source) {
        if (source == null) return null
        BitSet encoder = getUrlEncoder()
        StringBuilder buf = new StringBuilder(source.length())
        Fx.utils.toUTF8Bytes(source).each { Byte raw ->
            int b = raw.intValue() & 0xFF
            if (encoder.get(b)) {
                buf.append((char) b)
            } else if (b == 32) {
                buf.append("%20")
            } else {
                buf.append("%")
                buf.append(CONST_ENCODE.charAt(b >> 4))
                buf.append(CONST_ENCODE.charAt(b & 15))
            }
        }
        return buf.toString()
    }

    /** 构建排序查询参数字符串 */
    private static String buildQueryString(TreeMap queryMap) {
        StringBuilder sb = new StringBuilder()
        queryMap.each { key, value ->
            if (sb.length() > 0) sb.append("&")
            sb.append(signStringEncoder(key as String))
                    .append("=")
                    .append(signStringEncoder(value as String))
        }
        return sb.toString()
    }
