}
Map taskMap = taskRet.dataList[0] as Map;
log.info("外呼任务："+taskMap)
List taskDistributionScope = taskMap.task_distribution_scope__c as List;
log.info("外呼任务分发范围："+taskDistributionScope)

//查询所有未分配的外呼任务明细
def taskDetailRet = Fx.object.find(
  "task_detail__c",
  FQLAttribute.builder()
    .columns(["_id","owner","priority_level__c","customer_grading__c"])
    .orderBy(["owner": 1,"priority_level__c": -1,"customer_grading__c":1])
    .queryTemplate(QueryTemplate.AND(["task__c": QueryOperator.EQ(taskMap._id as String)],["owner": QueryOperator.IN(taskDistributionScope)],["task_status__c": QueryOperator.EQ("option_unassigned__c")]))
    .build(),
  SelectAttribute.builder()
    .fillExtendInfo(true)
    .searchRichTextExtra(true)
    .build()
).result() as QueryResult
//log.info("查询任务明细：" + taskDetailRet);
if (taskDetailRet == null) {
  log.info("没有符合条件的任务明细")
  return
}
List taskDetailList = taskDetailRet.dataList as List;
String currentOwner = ""
Integer taskCount = 0
taskDetailList.each {
  item ->
  Map taskDetailMap = item as Map;
  log.info("外呼任务明细："+taskDetailMap)
  Map ownerMap = taskDetailMap.owner__r as Map;
  if(currentOwner != ownerMap.name){
    currentOwner = ownerMap.name as String
    taskCount = 0 //重置计数器
    log.info("为销售分配任务："+currentOwner)
  }
  Integer taskLimit = Fx.global.findByApiName("var_task_limit__g")[1] as Integer
  if( taskCount < taskLimit ){
    taskCount ++ //计数器加一
    log.info("正在分配第"+taskCount+"个任务")
    def (Boolean error, Map data, String errorMessage) = Fx.object.update("task_detail__c", 
                                                                          taskDetailMap._id as String, 
                                                                          ["task_status__c": "option_already_assigned__c","allocation_time__c":DateTime.now()], 
                                                                  UpdateAttribute.builder()
                                                                          .triggerWorkflow(true)
                                                                          .build())
    if (error) {
      log.info("任务分配失败:" + errorMessage)
      taskCount --
    }else{
      log.info("任务分配成功")
    }
  }
}

