/**
 * @type classes
 * @returntype
 * @namespace library
 */
class PubLibTaskOutboundCallTaskDetailsGenerati {


    static String createCallOutTasks(List<String> taskList) {
        if(taskList == null || taskList.size() == 0) {
          log.info("未发现任务清单，终止生成。")
          return ["result":"failed","message":"未发现任务清单，终止生成。"]
        }
        log.info("收到任务"+taskList.size()+"条")
        def taskRet = Fx.object.find(
          "task__c",
          FQLAttribute.builder()
            .columns(["_id", "task_distribution_scope__c","task_name__c","task_material__c"])
            .queryTemplate(QueryTemplate.AND(["_id": QueryOperator.IN(taskList)]))
            .build(),
          SelectAttribute.builder()
            .fillExtendInfo(true)
            .searchRichTextExtra(true)
            .build()
        ).result() as QueryResult
        log.info("任务清单："+taskRet)
        List tasks = taskRet.dataList as List
        tasks.each {
          task ->
          Map taskMap = task as Map
          String taskId = taskMap._id as String
          String taskName = taskMap.task_name__c
          log.info("为任务《"+taskName+"》生成任务明细")
          log.info("任务分发范围:"+taskMap.task_distribution_scope__c)
          List distributionScope = taskMap.task_distribution_scope__c as List
          Map taskCount = [:]
          distributionScope.each {
            item ->
            String ownerId = item as String
            taskCount.put(ownerId, 0)
          }
          log.info("任务分发计数器:"+taskCount)
          def accRet = Fx.object.find(
            "AccountObj",
            FQLAttribute.builder()
              .columns(["_id", "customer_tiering__c","name","owner"])
              .orderBy(["customer_tiering__c": 1])
              .queryTemplate(QueryTemplate.AND(["owner": QueryOperator.IN(taskMap.task_distribution_scope__c)]))
              .build(),
            SelectAttribute.builder()
              .fillExtendInfo(true)
              .build()
          ).result() as QueryResult
          if( accRet.size > 0){
            List accs = accRet.dataList as List
            log.info("客户清单："+accs)
            accs.each {
              acc ->
              String accId = acc["_id"] as String
              String accOwner = (acc["owner"] as List)[0] as String
              String accName = acc["name"] as String
              String accCustomerTering = acc["customer_tiering__c"] as String
              log.info("客户名称："+accName)
              log.info("客户分级："+accCustomerTering)
              log.info("客户负责人："+accOwner)
              Date endDate = Date.now()
              if( accCustomerTering == "option_tier_1__c"){
                endDate = endDate + 7.days
              }else if( accCustomerTering == "option_tier_2__c"){
                endDate = endDate + 14.days
              }else if( accCustomerTering == "option_tier_3__c"){
                endDate = endDate + 21.days
              }else if( accCustomerTering == "option_tier_4__c"){
                endDate = endDate + 28.days
              }
              Map taskDetail = [
                "field_customer__c": accId,
                "field_customer_level__c": accCustomerTering,
                "field_customer_owner__c": accOwner,
                "task__c": taskId,
                "task_period_start_date__c": Date.now(),
                "task_material__c": taskMap.task_material__c as String,
                "allocation_time__c": DateTime.now(),
                "task_cycle_end_date__c":  endDate,
                "customer__c": accId,
                "owner": acc["owner"]
              ]
              def taskDetailRet = Fx.object.create("task_detail__c", taskDetail, null, CreateAttribute.builder().build()).result() as Map
              log.info("任务明细创建结果："+taskDetailRet)
            }
          }else{
            log.info("未找到有效客户")
          }
        }
        return ["result":"success","message":"成功生成任务明细。"]
    }

    //debug 时候的入口方法
    static void main(String[] args) {
      createCallOutTasks(["699d3be1c1a4750007622339"])
    }

}

